#include<bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin>>n;
    int a[5001],f[5001];
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    int ans=0;
    for (int i=1;i<=n;i++){
        f[i] = 1;
        for (int j=1;j<=i-1;j++){
            if (a[i]>a[j]){
                f[i]=max(f[i],f[j]+1);
            }
        ans=max(ans,f[i]);
        }
    }
    cout<<ans<<endl;
}
